#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, P, Q;
        scanf("%d %d %d", &N, &P, &Q);
        long long A[N], B[Q / 64 + 2], prefix[N + 1];
        prefix[0] = 1;
        for (int i = 0; i < N; i++) {
            scanf("%lld", &A[i]);
            prefix[i + 1] = (prefix[i] * A[i]) % P;
        }
        for (int i = 0; i < Q / 64 + 2; i++) {
            scanf("%lld", &B[i]);
        }
        long long x = 0;
        int Li, Ri;
        for (int i = 0; i < Q; i++) {
            if (i % 64 == 0) {
                Li = (B[i / 64] / 64 + x) % N;
                Ri = (B[i / 64] / 64 + 1 + x) % N;
            } else {
                Li = (Li + x) % N;
                Ri = (Ri + x) % N;
            }
            if (Li > Ri) {
                int temp = Li;
                Li = Ri;
                Ri = temp;
            }
            long long product = (prefix[Ri + 1] * powMod(prefix[Li], P - 2, P)) % P;
            x = (product + 1) % P;
        }
        printf("%lld\n", x);
    }
    return 0;
}

