import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int P = sc.nextInt();
            int Q = sc.nextInt();
            long[] A = new long[N];
            long[] B = new long[Q / 64 + 2];
            long[] prefix = new long[N + 1];
            prefix[0] = 1;
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextLong();
                prefix[i + 1] = (prefix[i] * A[i]) % P;
            }
            for (int i = 0; i < Q / 64 + 2; i++) {
                B[i] = sc.nextLong();
            }
            long x = 0;
            int Li, Ri;
            for (int i = 0; i < Q; i++) {
                if (i % 64 == 0) {
                    Li = (int) ((B[i / 64] / 64 + x) % N);
                    Ri = (int) ((B[i / 64] / 64 + 1 + x) % N);
                } else {
                    Li = (Li + (int) x) % N;
                    Ri = (Ri + (int) x) % N;
                }
                if (Li > Ri) {
                    int temp = Li;
                    Li = Ri;
                    Ri = temp;
                }
                long product = (prefix[Ri + 1] * powMod(prefix[Li], P - 2, P)) % P;
                x = (product + 1) % P;
            }
            System.out.println(x);
        }
    }
    public static long powMod(long a, long b, long p) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1) res = (res * a) % p;
            a = (a * a) % p;
            b >>= 1;
        }
        return res;
    }
}

