        prefix.push((prefix[prefix.length - 1] * A[i]) % P);
    }
    let x = 0n;
    let Li, Ri;
    for (let i = 0; i < Q; i++) {
        if (i % 64n == 0n) {
            Li = (B[i / 64n] / 64n + x) % N;
